mapper.select:
select
    coalesce(sum(case when type = 1 then amount else 0 end), 0) as totalIncome,
    coalesce(sum(case when type = 2 then amount else 0 end), 0) as totalExpense,
    count(1) as billCount
from bill
where user_id = #{userId}
  and is_deleted = 0
  and record_time  >=  #{startTime}
  and record_time  <=  #{endTime}

select
    sc.name as categoryName,
    coalesce(sum(b.amount), 0) as amount
from bill b
left join system_category sc on b.category_id = sc.id
where b.user_id = #{userId}
  and b.type = #{type}
  and b.is_deleted = 0
  and b.record_time  >=  #{startTime}
  and b.record_time  <=  #{endTime}
group by b.category_id, sc.name
order by amount desc
